[
  {
    "id": "conflict-002-moisture-cause",
    "title": "卫生间墙角潮湿成因及防水责任归属争议",
    "description": "双方对2026年6月5日复验时主卫生间墙角仍存在的轻微潮湿水印成因存在直接对立：周敏认为系装修防水不合格且未收到完整闭水试验记录，主张装修施工方应承担防水质量责任；雅居装饰则认为潮湿来自楼体公共管道而非装修防水范围，主张该现象不属于装修质量瑕疵。双方均未提供权威第三方检测或鉴定结论，潮湿成因与防水责任归属处于未决状态。",
    "actorIds": ["actor-002-owner", "actor-002-contractor"]
  },
  {
    "id": "conflict-002-rectification-acceptance",
    "title": "整改效果是否达到竣工验收条件的争议",
    "description": "双方对2026年6月2日雅居装饰发出的整改完成通知所涉整改效果是否满足整体竣工验收合格条件存在分歧：雅居装饰主张已重新处理防水节点、更换空鼓墙砖并修补墙面裂纹，整改已完成；周敏则主张复查时卫生间墙角仍有轻微潮湿且未收到完整闭水试验记录，整改未达到验收合格标准。双方对工程是否达到验收合格条件、是否存在剩余质量瑕疵未形成一致意见。",
    "actorIds": ["actor-002-owner", "actor-002-contractor"]
  },
  {
    "id": "conflict-002-final-payment",
    "title": "4万元尾款支付条件的争议",
    "description": "双方对2026年6月2日整改完成通知所附尾款支付请求是否成立存在直接对立：雅居装饰主张整改已完成、周敏应办理验收并支付剩余4万元尾款；周敏以防水质量不合格、整改未完成且未收到闭水试验记录为由继续拒付尾款。尾款的支付条件是否已成就处于未决状态。",
    "actorIds": ["actor-002-owner", "actor-002-contractor"]
  },
  {
    "id": "conflict-002-schedule-delay",
    "title": "2026年5月10日之后工期延期责任归属争议",
    "description": "双方对2026年5月25日雅居装饰发送竣工验收通知较补充协议约定的2026年5月10日晚15日的延期责任归属存在对立：周敏认为补充协议已涵盖变更所需时间，且之后未同意继续顺延，不认可额外延期；雅居装饰主张周敏后续多次调整材料颜色、延迟确认柜门样式实际影响施工进度，应由业主承担延期后果。现有材料中未见双方签字确认的再次顺延文件，5月10日之后工期顺延的事实基础及责任承担处于未决状态。",
    "actorIds": ["actor-002-owner", "actor-002-contractor"]
  },
  {
    "id": "conflict-002-supplement-change-scope",
    "title": "后续新增变更书面确认义务的履行争议",
    "description": "双方对2026年3月15日补充协议所约定'后续新增变更应通过书面记录确认'条款的履行存在分歧：雅居装饰主张周敏后续多次口头调整材料颜色、延迟确认柜门样式构成应予顺延工期的新增变更；周敏则主张后续未发生书面确认的新增变更，亦未同意相应顺延。该条款项下是否存在有效书面确认的新增变更及其范围处于未决状态。",
    "actorIds": ["actor-002-owner", "actor-002-contractor"]
  }
]
